using EmailMarketing.Modules.Contacts.Domain;
using EmailMarketing.Modules.Contacts.Events;
using EmailMarketing.Shared.Abstractions;
using MediatR;

namespace EmailMarketing.Modules.Contacts.Services
{
    public class ContactService
    {
        private readonly ApplicationDbContext _dbContext;
        private readonly IMediator _mediator;

        public ContactService(ApplicationDbContext dbContext, IMediator mediator)
        {
            _dbContext = dbContext;
            _mediator = mediator;
        }

        public async Task<Contact> CreateAsync(CreateContactDto dto)
        {
            var contact = new Contact(dto.Email, dto.FirstName, dto.LastName);
            _dbContext.Contacts.Add(contact);
            await _dbContext.SaveChangesAsync();

            // Publish event - other modules can subscribe
            await _mediator.Publish(new ContactCreatedEvent(
                contact.Id,
                contact.Email,
                contact.FirstName));

            return contact;
        }
    }
}

public class ContactCreatedEvent : INotification
{
    public Guid ContactId { get; }
    public string Email { get; }
    public string FirstName { get; }

    public ContactCreatedEvent(Guid contactId, string email, string firstName)
    {
        ContactId = contactId;
        Email = email;
        FirstName = firstName;
    }
}
